BA_GAMES.push({id:19,n:'速算挑战',ic:'🧮',cat:'数学',t:BA_GAME_SEC,ini2:()=>{const a=document.getElementById('ba-g-area');a.innerHTML='';a.style.cssText='min-height:240px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;background:#fafaf9';baGScr=0;baGAct=true;gT2(BA_GAME_SEC);function nq(){if(!baGAct)return;const ops=['+','-','×'];const op=ops[Math.floor(Math.random()*3)];let a2,b2,an2;if(op==='+'){a2=Math.floor(Math.random()*50)+10;b2=Math.floor(Math.random()*50)+10;an2=a2+b2}else if(op==='-'){a2=Math.floor(Math.random()*50)+30;b2=Math.floor(Math.random()*30)+1;an2=a2-b2}else{a2=Math.floor(Math.random()*9)+2;b2=Math.floor(Math.random()*9)+2;an2=a2*b2}a.innerHTML='<div style="font-size:30px;font-weight:800">'+a2+' '+op+' '+b2+' = ?</div><input id="ma2" style="font-size:22px;width:130px;padding:7px;text-align:center;border:2px solid #e5e5ea;border-radius:9px" placeholder="?"><button class="bs bb" style="font-size:13px;margin-top:5px" onclick="var v=parseInt(document.getElementById(\'ma2\').value);if(v==='+an2+'){baGScr+=2}else{baGScr=Math.max(0,baGScr-1)}document.getElementById(\'ba-g-score\').textContent=\'⏱\'+baGDur+\'s|\'+baGScr;nq()">确认</button>'}nq()}});
BA_GAMES.push({id:20,n:'比大小',ic:'📏',cat:'数学',t:BA_GAME_SEC,ini2:()=>{const a=document.getElementById('ba-g-area');a.innerHTML='';a.style.cssText='min-height:240px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:14px;background:#fafaf9';baGScr=0;baGAct=true;gT2(BA_GAME_SEC);function nq2(){if(!baGAct)return;const n1=Math.floor(Math.random()*900)+10,n2=Math.floor(Math.random()*900)+10;a.innerHTML='<div style="font-size:26px;font-weight:800">'+n1+' ? '+n2+'</div><div style="display:flex;gap:10px"><button style="font-size:18px;padding:10px 22px;background:#2a78d6;color:#fff;border:none;border-radius:12px;min-height:44px;cursor:pointer" onclick="if('+n1+'>'+n2+'){baGScr+=1}else{baGScr=Math.max(0,baGScr-1)}nq2()">＞</button><button style="font-size:18px;padding:10px 22px;background:#e34948;color:#fff;border:none;border-radius:12px;min-height:44px;cursor:pointer" onclick="if('+n1+'<'+n2+'){baGScr+=1}else{baGScr=Math.max(0,baGScr-1)}nq2()">＜</button><button style="font-size:18px;padding:10px 22px;background:#0ca30c;color:#fff;border:none;border-radius:12px;min-height:44px;cursor:pointer" onclick="if('+n1+'==='+n2+'){baGScr+=2}else{baGScr=Math.max(0,baGScr-1)}nq2()">＝</button></div>'}nq2()}});
BA_GAMES.push({id:21,n:'九九乘法',ic:'✖️',cat:'数学',t:BA_GAME_SEC,ini2:()=>{const a=document.getElementById('ba-g-area');a.innerHTML='';a.style.cssText='min-height:240px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;background:#fafaf9';baGScr=0;baGAct=true;gT2(BA_GAME_SEC);function nq3(){if(!baGAct)return;const n1=Math.floor(Math.random()*9)+1,n2=Math.floor(Math.random()*9)+1,an3=n1*n2;a.innerHTML='<div style="font-size:30px;font-weight:800">'+n1+' × '+n2+' = ?</div><input id="mm2" style="font-size:22px;width:110px;padding:7px;text-align:center;border:2px solid #e5e5ea;border-radius:9px" placeholder="?"><button class="bs bb" style="font-size:13px;margin-top:5px" onclick="var v=parseInt(document.getElementById(\'mm2\').value);if(v==='+an3+'){baGScr+=2}else{baGScr=Math.max(0,baGScr-1)}document.getElementById(\'ba-g-score\').textContent=\'⏱\'+baGDur+\'s|\'+baGScr;nq3()">确认</button>'}nq3()}});
BA_GAMES.push({id:22,n:'数字排序',ic:'🔤',cat:'数学',t:BA_GAME_SEC,ini2:()=>{const a=document.getElementById('ba-g-area');a.innerHTML='';a.style.cssText='min-height:240px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;background:#fafaf9';baGScr=0;baGAct=true;gT2(BA_GAME_SEC);function nq4(){if(!baGAct)return;const ns=[];for(let k=0;k<5;k++)ns.push(Math.floor(Math.random()*99)+1);const srt=[...ns].sort((a2,b2)=>a2-b2);a.innerHTML='<div style="font-size:12px;margin-bottom:4px">从小到大排列：</div><div style="display:flex;gap:5px;flex-wrap:wrap;justify-content:center">'+ns.map((n,i)=>'<button style="font-size:15px;padding:8px 10px;background:#f0f0ee;border:none;border-radius:9px;min-height:40px;cursor:pointer" id="ns'+i+'" onclick="var b=document.getElementById(\'ns'+i+'\');b.style.background=b.style.background===\'rgb(42,120,214)\'?\'#f0f0ee\':\'#2a78d6\';b.style.color=b.style.color===\'rgb(255,255,255)\'?\'#000\':\'#fff\'">'+n+'</button>').join('')+'</div><button class="bs bb" style="font-size:12px;margin-top:4px" onclick="var sl=[];for(var i=0;i<5;i++){var b=document.getElementById(\'ns\'+i);if(b&&b.style.background===\'rgb(42,120,214)\')sl.push(parseInt(b.textContent))}if(sl.length===5&&sl.every(function(v,i){return v==='+JSON.stringify(srt)+'[i]})){baGScr+=4}else if(sl.length===5){baGScr=Math.max(0,baGScr-2)}document.getElementById(\'ba-g-score\').textContent=\'⏱\'+baGDur+\'s|\'+baGScr;nq4()">✅提交</button>'}nq4()}});
BA_GAMES.push({id:23,n:'找质数',ic:'🔢',cat:'数学',t:BA_GAME_SEC,ini2:()=>{const a=document.getElementById('ba-g-area');a.innerHTML='';a.style.cssText='min-height:240px;display:flex;flex-wrap:wrap;gap:6px;align-items:center;justify-content:center;padding:12px;background:#fafaf9';baGScr=0;baGAct=true;gT2(BA_GAME_SEC);const pl=[];for(let i=2;i<=50;i++){let ip=true;for(let j=2;j*j<=i;j++){if(i%j===0){ip=false;break}}pl.push({n:i,p:ip})}function nr5(){const qs=pl.sort(()=>Math.random()-.5).slice(0,12);a.innerHTML='';qs.forEach(q=>{const b=document.createElement('button');b.style.cssText='font-size:14px;padding:7px 10px;border-radius:9px;border:2px solid #e5e5ea;background:#fff;cursor:pointer;min-width:40px;min-height:40px';b.textContent=q.n;b.addEventListener('pointerdown',function(){if(!baGAct)return;if(q.p){b.style.background='#0ca30c';b.style.color='#fff';baGScr+=2}else{b.style.background='#e34948';b.style.color='#fff';baGScr=Math.max(0,baGScr-1)}b.disabled=true;b.style.opacity='.6';document.getElementById('ba-g-score').textContent='⏱'+baGDur+'s|'+baGScr;if(Array.from(a.children).every(c=>c.disabled))nr5()});a.appendChild(b)})}nr5()}});
BA_GAMES.push({id:24,n:'凑24点',ic:'🎯',cat:'数学',t:BA_GAME_SEC,ini2:()=>{const a=document.getElementById('ba-g-area');a.innerHTML='';a.style.cssText='min-height:240px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:8px;background:#fafaf9';baGScr=0;baGAct=true;gT2(BA_GAME_SEC);function nq5(){const ns=[];for(let i=0;i<4;i++)ns.push(Math.floor(Math.random()*9)+1);a.innerHTML='<div style="font-size:26px;font-weight:800;letter-spacing:6px">'+ns.join(' ')+'</div><div style="font-size:12px;color:var(--i3)">用+ - × ÷ 使结果=24</div><div style="display:flex;gap:6px"><button style="font-size:15px;padding:8px 16px;min-height:42px;background:#0ca30c;color:#fff;border:none;border-radius:9px;cursor:pointer" onclick="baGScr+=5;document.getElementById(\'ba-g-score\').textContent=\'⏱\'+baGDur+\'s|\'+baGScr;nq5()">✅ 做出来了</button><button style="font-size:15px;padding:8px 16px;min-height:42px;background:#e34948;color:#fff;border:none;border-radius:9px;cursor:pointer" onclick="nq5()">🔄 换一题</button></div>'}nq5()}});
