BA_GAMES.push({id:25,n:'贪吃蛇',ic:'🐍',cat:'休闲',t:BA_GAME_SEC,ini2:()=>baGCvC({t:600,ini:(c,w,h,d)=>{d.sk=[{x:10,y:10},{x:9,y:10},{x:8,y:10}];d.dr={x:1,y:0};d.fd={x:5,y:5};d.gs=16;d.cs=Math.floor(w/d.gs);d.rs=Math.floor(h/d.gs);d.tk=0},upd:(c,w,h,d)=>{d.tk++;if(d.tk%8!==0)return;const hd={x:d.sk[0].x+d.dr.x,y:d.sk[0].y+d.dr.y};if(hd.x<0||hd.x>=d.cs||hd.y<0||hd.y>=d.rs||d.sk.some(s=>s.x===hd.x&&s.y===hd.y)){gEnd(baGScr);return}d.sk.unshift(hd);if(hd.x===d.fd.x&&hd.y===d.fd.y){baGScr+=3;d.fd={x:Math.floor(Math.random()*d.cs),y:Math.floor(Math.random()*d.rs)};document.getElementById('ba-g-score').textContent='⏱'+baGDur+'s|'+baGScr}else{d.sk.pop()}c.fillStyle='#0ca30c';d.sk.forEach(s=>c.fillRect(s.x*d.gs,s.y*d.gs,d.gs-2,d.gs-2));c.fillStyle='#e34948';c.fillRect(d.fd.x*d.gs,d.fd.y*d.gs,d.gs-2,d.gs-2)},clk:(x,y,d)=>{const dx=x-d.sk[0].x*d.gs,dy=y-d.sk[0].y*d.gs;if(Math.abs(dx)>Math.abs(dy)){d.dr={x:dx>0?1:-1,y:0}}else{d.dr={x:0,y:dy>0?1:-1}}}})});
BA_GAMES.push({id:26,n:'弹球打砖',ic:'🏓',cat:'休闲',t:BA_GAME_SEC,ini2:()=>baGCvC({t:600,ini:(c,w,h,d)=>{d.pd={x:w/2-40,y:h-30,w:80,h:12};d.bl={x:w/2,y:h-50,r:6,vx:3,vy:-3};d.br=[];for(let r=0;r<5;r++)for(let cl=0;cl<8;cl++)d.br.push({x:cl*50+5,y:r*25+10,w:46,h:20,al:1});d.mx=w/2},upd:(c,w,h,d)=>{d.pd.x=d.mx-d.pd.w/2;d.pd.x=Math.max(0,Math.min(w-d.pd.w,d.pd.x));d.bl.x+=d.bl.vx;d.bl.y+=d.bl.vy;if(d.bl.x<=d.bl.r||d.bl.x>=w-d.bl.r)d.bl.vx*=-1;if(d.bl.y<=d.bl.r)d.bl.vy*=-1;if(d.bl.y>=h-30-d.bl.r&&d.bl.x>=d.pd.x&&d.bl.x<=d.pd.x+d.pd.w){d.bl.vy*=-1;d.bl.y=h-30-d.bl.r-1}if(d.bl.y>h){gEnd(baGScr);return}d.br.forEach(b=>{if(b.al&&d.bl.x>b.x&&d.bl.x<b.x+b.w&&d.bl.y>b.y&&d.bl.y<b.y+b.h){b.al=0;d.bl.vy*=-1;baGScr+=2;document.getElementById('ba-g-score').textContent='⏱'+baGDur+'s|'+baGScr}});if(d.br.every(b=>!b.al)){baGScr+=10;for(let r=0;r<5;r++)for(let cl=0;cl<8;cl++)d.br.push({x:cl*50+5,y:r*25+10,w:46,h:20,al:1})}c.fillStyle='#2a78d6';c.fillRect(d.pd.x,d.pd.y,d.pd.w,d.pd.h);c.fillStyle='#e34948';c.beginPath();c.arc(d.bl.x,d.bl.y,d.bl.r,0,Math.PI*2);c.fill();['#f66','#ff9500','#fd0','#0ca30c','#4a3aa7'].forEach((cl,r)=>{c.fillStyle=cl;d.br.filter(b=>b.al&&Math.floor(b.y/25)===r).forEach(b=>c.fillRect(b.x,b.y,b.w,b.h))})},clk:()=>{},mv:1})});
BA_GAMES.push({id:27,n:'小鸟飞行',ic:'🐤',cat:'休闲',t:BA_GAME_SEC,ini2:()=>baGCvC({t:600,ini:(c,w,h,d)=>{d.bd={x:60,y:h/2,vy:0,r:12};d.pp=[];d.fm=0},upd:(c,w,h,d)=>{if(!baGAct)return;d.fm++;d.bd.vy+=.4;d.bd.y+=d.bd.vy;if(d.bd.y<0||d.bd.y>h){gEnd(baGScr);return}if(d.fm%60===0){d.pp.push({x:w,gp:80+Math.random()*60,gy:60+Math.random()*(h-160)});if(d.pp.length>4)d.pp.shift()}d.pp.forEach(p=>{p.x-=3;if(d.bd.x+d.bd.r>p.x&&d.bd.x-d.bd.r<p.x+40){if(d.bd.y-d.bd.r<p.gy||d.bd.y+d.bd.r>p.gy+p.gp){gEnd(baGScr);return}}if(p.x<-40){baGScr+=2;var sc=document.getElementById('ba-g-score');if(sc)sc.textContent='⏱'+baGDur+'s|'+baGScr}});d.pp=d.pp.filter(p=>p.x>-60);c.fillStyle='#87CEEB';c.fillRect(0,0,w,h);c.fillStyle='#fd0';c.beginPath();c.arc(d.bd.x,d.bd.y,d.bd.r,0,Math.PI*2);c.fill();c.fillStyle='#0ca30c';d.pp.forEach(p=>{c.fillRect(p.x,0,40,p.gy);c.fillRect(p.x,p.gy+p.gp,40,h-p.gy-p.gp)})},clk:(x,y,d)=>{d.bd.vy=-6}})});
BA_GAMES.push({id:28,n:'躲避陨石',ic:'☄️',cat:'休闲',t:BA_GAME_SEC,ini2:()=>baGCvC({t:600,ini:(c,w,h,d)=>{d.sp={x:w/2,y:h-40,w:30,h:30};d.rk=[];d.mx=w/2},upd:(c,w,h,d)=>{d.sp.x=d.mx-d.sp.w/2;d.sp.x=Math.max(0,Math.min(w-d.sp.w,d.sp.x));if(Math.random()<.05)d.rk.push({x:Math.random()*w,y:-20,r:10+Math.random()*15});d.rk.forEach(r=>{r.y+=3;if(r.y>h+20){baGScr+=1;document.getElementById('ba-g-score').textContent='⏱'+baGDur+'s|'+baGScr}});d.rk=d.rk.filter(r=>r.y<h+40);for(const r of d.rk){if(Math.abs(d.sp.x+d.sp.w/2-r.x)<r.r+15&&Math.abs(d.sp.y+d.sp.h/2-r.y)<r.r+15){gEnd(baGScr);return}}c.fillStyle='#2a78d6';c.beginPath();c.moveTo(d.sp.x+d.sp.w/2,d.sp.y);c.lineTo(d.sp.x+d.sp.w,d.sp.y+d.sp.h);c.lineTo(d.sp.x,d.sp.y+d.sp.h);c.closePath();c.fill();c.fillStyle='#888';d.rk.forEach(r=>{c.beginPath();c.arc(r.x,r.y,r.r,0,Math.PI*2);c.fill()})},clk:()=>{},mv:1})});
