BA_GAMES.push({id:29,n:'钓鱼达人',ic:'🎣',cat:'休闲',t:BA_GAME_SEC,ini2:()=>{const a=document.getElementById('ba-g-area');a.innerHTML='';a.style.cssText='min-height:260px;position:relative;overflow:hidden;background:linear-gradient(180deg,#87CEEB 60%,#1a5276 60%);cursor:pointer';baGScr=0;baGAct=true;gT2(BA_GAME_SEC);const f2=['🐟','🐠','🐡','🦈','🐋','🐙'];function sp2(){if(!baGAct)return;const f=document.createElement('div');f.style.cssText='position:absolute;font-size:26px;top:'+(40+Math.random()*40)+'%;left:-40px;transition:left '+(2+Math.random()*3)+'s linear;cursor:pointer;z-index:2';f.textContent=f2[Math.floor(Math.random()*f2.length)];const p2=f.textContent==='🦈'?5:f.textContent==='🐋'?4:f.textContent==='🐙'?3:1;f.addEventListener('pointerdown',function(e){e.preventDefault();if(!baGAct)return;baGScr+=p2;document.getElementById('ba-g-score').textContent='⏱'+baGDur+'s|'+baGScr;f.style.transform='scale(1.5)';f.style.opacity='0';setTimeout(()=>f.remove(),200)});a.appendChild(f);requestAnimationFrame(()=>{f.style.left=a.offsetWidth+'px'});setTimeout(()=>{if(f.parentNode)f.remove()},4000);baGData.ft2=setTimeout(sp2,800+Math.random()*1200)}sp2();baGData.cl=()=>{clearTimeout(baGData.ft2);while(a.firstChild)a.removeChild(a.firstChild)}}});
