function baPickRandomGame(){
  if(!BA_GAMES.length) return null;
  return BA_GAMES[Math.floor(Math.random()*BA_GAMES.length)];
}

function baPrepareGame(g){
  document.getElementById("ba-g-title").textContent=(g.ic||"🎮")+" "+g.n;
  document.getElementById("ba-g-score").textContent="⏱"+BA_GAME_SEC+"s|0";
  document.getElementById("ba-g-foot").textContent="类别:"+(g.cat||"休闲");
  document.getElementById("ba-g-btn").textContent="🎮 开始";
  document.getElementById("ba-g-btn").onclick=baStartPreparedGame;
  document.getElementById("ba-game-modal").classList.add("on");
  baGData._g=g;
}

function baStartPreparedGame(){
  var a=document.getElementById("ba-g-area");
  a.innerHTML="";
  if(baGData.cl) try{ baGData.cl(); }catch(e){}
  clearInterval(baGInt); clearTimeout(baGTm);
  if(baGRaf) cancelAnimationFrame(baGRaf);
  baGAct=false;
  var g=baGData._g;
  baGData={ _g:g };
  baGScr=0; baGDur=g.t||BA_GAME_SEC;
  a.style.cssText="min-height:240px";
  g.ini2();
  document.getElementById("ba-g-btn").textContent="游戏中…";
  document.getElementById("ba-g-btn").onclick=function(){};
}

function baCloseGameModal(){
  baGAct=false;
  clearInterval(baGInt); clearTimeout(baGTm);
  if(baGRaf) cancelAnimationFrame(baGRaf);
  if(baGData.cl) try{ baGData.cl(); }catch(e){}
  baGData={};
  document.getElementById("ba-game-modal").classList.remove("on");
}
